import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十一章 六十剑","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十一章-六十剑.md","filePath":"永恒道途/正文/第一卷-山门有路/第十一章-六十剑.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十一章-六十剑.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十一章-六十剑" tabindex="-1">第十一章 六十剑 <a class="header-anchor" href="#第十一章-六十剑" aria-label="Permalink to &quot;第十一章 六十剑&quot;">​</a></h1><p>与苏婉在白玉广场见过一面后，陈玄把日子过得比从前更安静。</p><p>天不亮，先去药园点卯。挑水、翻土、除虫、记册，一项都不能慢。鲁老头嘴上照旧骂他“手脚笨”，真正分活时却总把最乱的药畦留给他，说是“让你多长点眼力”；韩执事还是那副冷脸，药株少一片叶都要追责，半分情面不讲。</p><p>陈玄一句不辩。</p><p>他没有因为见过天灵根的强大便骤然增加练剑次数。相反，每日一百剑减到六十剑，吐纳与养脉的时间却多了一倍。</p><p>苏婉那句“也不代表一定走得到”没有让他愤怒，只让他更清楚一件事：伪灵根的路，经不起用暗伤换来的虚快。</p><p>日落后，他便上后山练剑台。山风穿袖，寒得像刀。他先吐纳一周天，再拔剑起手，把《青元剑诀》第一重拆成四步：行气、定势、凝锋、落斩。</p><p>行气最基础，灵力自少商起，经臂脉入剑。</p><p>定势最枯燥，肩背稍偏半寸，剑路就歪。</p><p>最难的始终是第三步，凝锋。</p><p>灵力每次冲到剑尖前三寸便散，像水撞漏斗，聚不住、压不住。夜里一百剑、两百剑练下来，他握剑的手都在发抖，剑尖仍只浮着一缕虚芒，连一张薄纸都切不开。</p><p>外门弟子偶尔路过，见他在寒夜里反复起手，总少不了几句议论。</p><p>“那不是药园陈玄吗？外门黑马？”</p><p>“黑马归黑马，剑修哪有这么好练。”</p><p>“杂灵根还想走纯剑路，心真大。”</p><p>陈玄不回头，只把剑握得更紧。</p><p>他不是听不见，也不是毫不在意。</p><p>只是那些议论说到底仍是旁人的判断。若他为了反驳每一句话多挥一剑，剑便不再握在自己手中，而是被所有开口的人牵着走。</p><p>他真正要对付的，是剑尖那三寸始终无法凝稳的灵力。</p><p>入冬后的第七夜，陈玄连斩一百二十剑，虎口旧裂再次崩开，血顺着剑柄往下淌。他正欲继续，松林里忽然走出一道灰袍身影。</p><p>许长老。</p><p>他是丁字药园名义上的主事长老，平日极少现身。陈玄入园近两年，只在每季清点灵药时远远见过几次。鲁老头提起他时从不称长老，只叫“姓许的药痴”。</p><p>老者站在石阶边看了他片刻，才开口：“你这不是练剑，是和自己较劲。”</p><p>陈玄收剑抱拳：“弟子愚钝，请长老指点。”</p><p>许长老没答，只俯身捻起一枚松针，屈指一弹。</p><p>松针破风而出，掠过丈许夜色，钉入木桩寸许，针尾仍在轻颤。</p><p>“看见了吗？”老者淡声道，“针轻，势却不断。你每一剑都想一口吃成胖子，灵力未稳先求爆发，当然会散。”</p><p>陈玄看向木桩。</p><p>松针没有被灵力裹得光芒四射，甚至没有完全穿透木面。可从老者指间到木桩的一丈距离，它的方向、速度与力量没有一丝浪费。</p><p>“弟子以为，凝锋便要把所有灵力压进剑尖。”</p><p>“水装不满破瓮。你经脉只能送来三分，偏要在剑尖挤出十分，剩下七分从哪里来？”许长老道，“凝，不是多。是不散。”</p><p>陈玄沉默几息，低声道：“弟子怕慢了，就追不上。”</p><p>“怕，不丢人。”许长老转身欲走，脚步微顿，“但剑不认怕。剑只认稳。”</p><p>说完，老者沿石阶下山，再没回头。</p><p>那一夜，陈玄没再出剑。</p><p>他盘坐崖边，从子时坐到天明，把这些时日每一次出手都在脑中拆开重走：哪一剑呼吸乱了，哪一剑肩背紧了，哪一剑心先急了。他一处处剥开，最后终于承认，自己一直在“抢”。</p><p>抢时间，抢资源，抢每一次翻身机会。</p><p>这种抢救过他的命，也让他的剑总悬在半空，落不进骨子。</p><p>他又想起广场上的那滴水。</p><p>苏婉用的灵力未必比他施展十次引水术更多，却恰好封住寒髓草叶片的裂纹。许长老的松针也是一样。力量强弱是一回事，能否把每一分力量送到该去的地方，是另一回事。</p><p>陈玄直到此刻才真正明白，自己与苏婉的差距并不只隔着三个小境界。</p><p>天亮后，他改法。</p><p>前半夜只吐纳，不出剑。</p><p>后半夜只练三十剑。每一剑都压呼吸走完整个小周天，出剑前先定步，落剑后不急收势，硬把一个“稳”字刻进筋骨。</p><p>起初更难。</p><p>三十剑练完，比过去两百剑还累，像把人从骨缝里榨干。</p><p>因为慢下来后，所有细小错误都无处藏身。</p><p>左脚落得太重，腰便先于肩转；吐息快半拍，灵力会在肘间鼓起；目光若只盯着木桩，剑路便会不自觉向内收。陈玄用白线在石台上标出脚位，又把一片枯叶悬在剑前三尺，要求每一剑落下时，风只能让叶片向后，不能向左右偏斜。</p><p>最初十剑，枯叶乱转。</p><p>十日后，它终于能沿同一条线向后飘落。</p><p>第十日，剑尖青芒第一次稳住三息。</p><p>第十六日，第一式“青锋起”能在落斩前维持青芒不散。</p><p>第二十八日，第二式“回云斩”第一次完整转折，剑锋没有因变向而失去青芒。</p><p>第三十七日，最耗神的“凝锋”终于不再断续，灵力被拧成一缕细线，能在青锋剑刃上停留五息。</p><p>药园、木屋、练剑台三点一线，陈玄把自己活成了钟摆。</p><p>鲁老头有一回夜里上后山寻酒，远远看见他在雪里站桩，骂了句“疯小子”；第二天却把一瓶止裂药膏塞进他药篓底层，嘴上还不忘补一句“别死在台上，省得我收尸”。</p><p>陈玄没道谢，只把药膏抹开，夜里照常上台。</p><p>此后几日，他每日都会在草棚桌上多放一小壶温水。鲁老头从不提药膏，他也不提温水。两个人一个照旧骂，一个照旧干活，仿佛那点不说出口的照拂从未发生。</p><p>入冬第三月末，后山连降两场雪。</p><p>那夜月色极亮，整片山脊都覆着冷白。陈玄立在石台中央，青锋平举，呼吸细得几不可闻。</p><p>第一剑，青芒如丝。</p><p>第二剑，丝意成线。</p><p>第三剑起势时，丹田里反复压炼的灵力忽然一紧，像被无形之手猛地箍住；下一瞬，束缚骤裂，热流沿经脉轰然奔涌，体内滞涩处同时贯通。</p><p>炼气五层，破。</p><p>突破刹那，青锋陡然清鸣，剑身震出一圈淡白霜雾。陈玄借势踏前半步，行气、定势、凝锋、落斩一气呵成。</p><p>“斩！”</p><p>一道完整青元剑气自剑锋吐出，横掠三尺雪面。前方石台“嗤”地裂开一道细长口，积雪被齐齐掀向两侧。月光落在裂痕上，像一瓣刚绽即灭的青莲。</p><p>陈玄握剑的手微微发颤。</p><p>颤抖既有灵力耗尽后的脱力，也有那一瞬无法完全压下的激动。过去数月，他在同一块石台上落过上万剑，绝大多数连积雪都只能扫开一层。如今那道三尺剑痕安静留在月光下，终于替所有无人看见的失败作了回答。</p><p>这不是运气，是《青元剑诀》第一层“青元成锋”真正入门。</p><p>陈玄没有立刻斩出第二剑。</p><p>方才那道剑气抽走了近三成灵力，右臂经脉也传来针扎般的刺痛。以他现在的修为，同样的剑气最多再出两次；若三剑杀不了敌，先失去战力的便是自己。</p><p>他把这份代价牢牢记住。</p><p>随后，他从第一剑的吐息开始复盘，没有因为成功便忽略右肩比平时早转了半分。喜悦可以留到天亮，错误必须在下一剑之前看见。</p><p>可兴奋只持续了几息。他立刻收剑盘膝，把新境气机一点点压稳。</p><p>外门的规矩他比谁都清楚。炼气五层，顶多让他从“任人拿捏”变成“勉强上桌”，离安全还远。</p><p>天亮回药园，鲁老头一眼看出他气息变化，咧嘴问：“破境了？”</p><p>“昨夜侥幸。”</p><p>“侥幸个屁。”鲁老头一巴掌拍他后背，“你这几月怎么熬的，老子都看在眼里。熬出来的本事，比捡来的硬。”</p><p>话音刚落，韩执事从药畦尽头走来，袖中抖出一卷青木卷轴，啪地落在陈玄掌心。</p><p>“任务殿新悬赏，猎杀二阶裂齿獠熊，取胆囊一枚。”韩执事语气平平，“炼气五层，够资格报。”</p><p>陈玄展开卷轴。</p><p>外门贡献三十点，中品回灵丹一枚。</p><p>报酬不低，风险更高。</p><p>二阶裂齿獠熊，成年后至少相当于炼气七层。任务要求三人以上组队，队中还必须有两名炼气六层。以陈玄如今的修为，正面对上连一掌都撑不住。</p><p>可三十点贡献足够换一瓶固脉丹。更重要的是，内门预选除了修为，还看任务履历。药园出身的弟子若想让各峰执事看到，不能永远只在灵田里证明自己。</p><p>韩执事看着他，眼神冷硬：“你可以不接。但内门预选看近三月评绩，光在药园抡锄头，修为再高也只是杂役。”</p><p>陈玄把卷轴卷回，收进怀里：“弟子接。”</p><p>“明早卯时，任务殿报到。”韩执事顿了一下，补上一句，“黑风山不是擂台，没人会给你第二次失误。”</p><p>傍晚，陈玄下山去茶摊见王胖子。</p><p>胖子听完差点把茶喷出来：“裂齿獠熊？那玩意皮厚爪重，炼气六层遇上都得绕道。你刚到五层就去？”</p><p>“所以我不硬拼。”</p><p>“你每次说不硬拼，我都要少睡三天。”王胖子骂骂咧咧，从怀里摸出一包符纸，“两张烟遁符，一张护身符，按本钱给你。灵石以后再算，先把命带回来。”</p><p>陈玄接过符纸，指尖微顿：“这份情，我记着。”</p><p>胖子翻了个白眼：“少整这套。真要记情，就给我带点值钱妖材，别回回带伤回来要我贴药钱。”</p><p>陈玄难得笑了一下，点头应下。</p><p>夜深回屋，他把青锋剑、短刀、乌鳞草粉、止血散、符纸一件件摊在桌上，按先后顺序反复确认。任务卷轴旁，压着一张手绘黑风山简图，几条备用撤退线被红笔圈得清清楚楚。</p><p>他又把队伍中两名同伴的资料写在另一张纸上。</p><p>陆炳，炼气六层，外门任务排名四十一，惯用厚背刀；郑衡，炼气六层，擅符阵，过去一年完成过三次猎妖任务。两人经验都比他多，却从未与他合作。</p><p>陌生同伴不是敌人，也不能因为同门身份便毫无防备。</p><p>进山之后，他既要看妖兽，也要看人。</p><p>掌天瓶贴在胸口，冰凉沉静。</p><p>陈玄抬手按了按衣襟，心里那点破境后的躁意被这股凉意慢慢压平。</p><p>窗外北风卷雪，木门轻响。</p><p>他看着桌上的卷轴，目光一点点沉定。</p><p>下一步要争的，已经不只是修为。</p><p>是命。</p><p>（第十一章完）</p>',108)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
